
clear
syms x y 
f = 5*x^2 - 6*x*y + 5*y^2 %[output:16012bb5]

syms p_x p_y lambda
phi_x = 5*lambda^2 + (10*p_x - 6*p_y)*lambda + (5*p_x^2 - 6 * p_x * p_y + 5 * p_y^2) %[output:34d7aa33]
phi_y = 5*lambda^2 + (10*p_y - 6*p_x)*lambda + (5*p_x^2 - 6 * p_x * p_y + 5 * p_y^2) %[output:93f22be1]

F = matlabFunction(f) %[output:45c8b00a]
phi_x = matlabFunction(phi_x) %[output:1b723699]
phi_y = matlabFunction(phi_y) %[output:00a35353]

p = [-1 -1];
f = @(lambda) phi_x(lambda, p(1), p(2));
[p(1), b, n] = gss(f, -1, 2, 0.0001) %[output:484a03d9] %[output:1dcdcd0c] %[output:4be9eed1]

f = @(lambda) phi_y(lambda, p(1), p(2));
[p(2), b, n] = gss(f, -1, 2, 0.0001, 1000, true, []);

p %[output:8c0707d0]

%%
[X,Y] = meshgrid(linspace(-5, 5, 20));
Z = F(X, Y);
surf(X,Y,Z) %[output:0879a991]


